// T617 FlowCanvasWriter — 2-guard write gate
const FLOW_IMMUTABLE_STATES = ['PUBLISHED'] as const;

async updateCanvas(flowId: string, nodes: Record<string, unknown>[], edges: Record<string, unknown>[]): Promise<DataProcessResult<Record<string, unknown>>> {
  const tenantId = this.tenantContext.getTenantId(); // ALS only — never from payload

  // ORDER 1: BOLA — verify requesting tenant owns the flow
  const flowResult = await this.db.searchDocuments('flows', { flowId });
  if (!flowResult.data?.length) return DataProcessResult.failure('FLOW_NOT_FOUND', ...);
  const flow = flowResult.data[0];
  if (flow['tenantId'] !== tenantId) {
    await this.queue.enqueue('FlowImmutableRejected', { flowId, tenantId, reason: 'BOLA_VIOLATION' });
    return DataProcessResult.failure('BOLA_VIOLATION', 'Tenant does not own this flow');
  }

  // ORDER 2: FLOW_IMMUTABLE guard — PUBLISHED is one-way
  const flowStatus = flow['status'] as string;
  if (FLOW_IMMUTABLE_STATES.includes(flowStatus as 'PUBLISHED')) {
    await this.queue.enqueue('FlowImmutableRejected', { flowId, tenantId, reason: 'IMMUTABLE_STATE', currentStatus: flowStatus });
    return DataProcessResult.failure('FLOW_IMMUTABLE', `Flow is ${flowStatus} and cannot be modified`);
  }

  // DNA-8: audit BEFORE enqueue
  await this.db.storeDocument('canvas-audit', { flowId, tenantId, action: 'CANVAS_UPDATED', nodeCount: nodes.length, edgeCount: edges.length });
  await this.queue.enqueue('FlowCanvasUpdated', { flowId, tenantId, nodeCount: nodes.length, edgeCount: edges.length });
  return DataProcessResult.success({ flowId, tenantId });
}
